import React, { useState, useEffect, useContext } from 'react';
import api from '../utils/api';
import { AuthContext } from '../context/AuthContext';
import { Link, useNavigate } from 'react-router-dom';
import NearbyWorkersModal from '../components/NearbyWorkersModal';
import ServiceEstimatorModal from '../components/ServiceEstimatorModal';
import JobLocationMap from '../components/JobLocationMap';
import AIChat from '../components/AIChat';
import './Dashboard.css';

const EmployerDashboard = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [stats, setStats] = useState(null);
  const [recentJobs, setRecentJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEmergency, setIsEmergency] = useState(false);
  const [isEstimatorOpen, setIsEstimatorOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [topWorkers, setTopWorkers] = useState([]);
  const [activeJobs, setActiveJobs] = useState([]);
  const [upcomingPayments, setUpcomingPayments] = useState([]);
  const [profileSettings, setProfileSettings] = useState({
    name: user?.name || '',
    email: user?.email || '',
    phone: user?.phone || '',
    company: user?.company || '',
    notifications: true,
    emailUpdates: true
  });
  const [isAIChatOpen, setIsAIChatOpen] = useState(false);

  useEffect(() => {
    if (activeTab === 'dashboard') {
      fetchDashboardData();
    }
  }, [activeTab]);

  const fetchDashboardData = async () => {
    try {
      const response = await api.get('/employers/dashboard');
      setStats(response.data.stats);
      setRecentJobs(response.data.recentJobs);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const categories = [
    { id: 'painting', label: 'Painting', icon: '🎨', color: '#3B82F6' },
    { id: 'electrical', label: 'Electrical', icon: '⚡', color: '#F59E0B' },
    { id: 'masonry', label: 'Masonry', icon: '🧱', color: '#EF4444' },
    { id: 'plumbing', label: 'Plumbing', icon: '🚰', color: '#10B981' },
    { id: 'carpentry', label: 'Carpentry', icon: '🪚', color: '#8B5CF6' },
    { id: 'welding', label: 'Welding', icon: '🔥', color: '#F97316' },
    { id: 'construction', label: 'Construction', icon: '🏗️', color: '#6B7280' },
    { id: 'cleaning', label: 'Cleaning', icon: '🧹', color: '#EC4899' },
    { id: 'gardening', label: 'Gardening', icon: '🌱', color: '#10B981' },
    { id: 'loading', label: 'Loading', icon: '📦', color: '#8B5CF6' },
    { id: 'fabrication', label: 'Fabrication', icon: '🛠️', color: '#06B6D4' },
    { id: 'tiling', label: 'Tiling', icon: '📐', color: '#DC2626' }
  ];

  useEffect(() => {
    if (activeTab === 'dashboard') {
      fetchDashboardData();
      fetchAdditionalData();
    }
  }, [activeTab]);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const handleProfileChange = (field, value) => {
    setProfileSettings(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const saveProfileSettings = async () => {
    try {
      // Here you would typically make an API call to save settings
      console.log('Saving profile settings:', profileSettings);
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000));
      alert('Settings saved successfully!');
    } catch (error) {
      console.error('Error saving settings:', error);
      alert('Error saving settings');
    }
  };

  const fetchAdditionalData = async () => {
    try {
      // Fetch notifications
      try {
        const notificationsResponse = await api.get('/chat/notifications');
        setNotifications(notificationsResponse.data.notifications || []);
      } catch (notificationsError) {
        console.error('Error fetching notifications:', notificationsError);
        // Set mock data if API fails
        setNotifications([
          { id: 1, icon: '✅', message: 'New application received for Painting job', time: '2 mins ago', type: 'application' },
          { id: 2, icon: '💼', message: 'Your construction job has been completed', time: '1 hour ago', type: 'completion' }
        ]);
      }

      // Fetch top workers
      try {
        const topWorkersResponse = await api.get('/workers/top-rated');
        setTopWorkers(topWorkersResponse.data.workers || []);
      } catch (workersError) {
        console.error('Error fetching top workers:', workersError);
        setTopWorkers([]);
      }

      // Fetch active jobs
      try {
        const activeJobsResponse = await api.get('/employers/active-jobs');
        setActiveJobs(activeJobsResponse.data.jobs || []);
      } catch (jobsError) {
        console.error('Error fetching active jobs:', jobsError);
        setActiveJobs([]);
      }

      // Fetch upcoming payments
      try {
        const paymentsResponse = await api.get('/payments/upcoming');
        setUpcomingPayments(paymentsResponse.data.payments || []);
      } catch (paymentsError) {
        console.error('Error fetching payments:', paymentsError);
        setUpcomingPayments([]);
      }
    } catch (error) {
      console.error('General error in fetchAdditionalData:', error);
    }
  };

  const activeCategory = categories.find(cat => cat.id === selectedCategory);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <>
            {/* Welcome Banner */}
            <div className="welcome-banner">
              <h1>Welcome back, {user?.name}!</h1>
              <p>Ready to hire skilled professionals for your projects today.</p>
            </div>

            {/* Stats Grid */}
            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-icon" style={{background: 'linear-gradient(135deg, #3B82F6, #60A5FA)'}}>
                  <span>📋</span>
                </div>
                <div className="stat-info">
                  <h3>Jobs Posted</h3>
                  <p className="stat-value">{stats?.totalJobsPosted || 0}</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon" style={{background: 'linear-gradient(135deg, #10B981, #34D399)'}}>
                  <span>💼</span>
                </div>
                <div className="stat-info">
                  <h3>Active Jobs</h3>
                  <p className="stat-value">{stats?.activeJobs || 0}</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon" style={{background: 'linear-gradient(135deg, #F59E0B, #FBBF24)'}}>
                  <span>💰</span>
                </div>
                <div className="stat-info">
                  <h3>Total Spent</h3>
                  <p className="stat-value">₹{stats?.totalSpent || 0}</p>
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-icon" style={{background: 'linear-gradient(135deg, #EF4444, #F87171)'}}>
                  <span>📝</span>
                </div>
                <div className="stat-info">
                  <h3>Pending Applications</h3>
                  <p className="stat-value">{stats?.pendingApplications || 0}</p>
                </div>
              </div>
            </div>

            {/* Notifications & Updates */}
            <div className="dashboard-sections">
              <div className="section-column">
                {/* Recent Activity */}
                <div className="activity-card">
                  <div className="card-header">
                    <h3>🔔 Recent Activity</h3>
                    <span className="notification-badge">{notifications.length}</span>
                  </div>
                  <div className="activity-list">
                    {notifications.slice(0, 5).map((notification, index) => (
                      <div key={notification._id || index} className="activity-item">
                        <div className="activity-icon">
                          {notification.type === 'job_accepted' ? '✅' : 
                           notification.type === 'job_rejected' ? '❌' : 
                           notification.type === 'job_assigned' ? '💼' : 
                           notification.type === 'new_application' ? '📝' : 
                           notification.type === 'job_completed' ? '🎉' : 
                           notification.type === 'new_message' ? '💬' : 'ℹ️'}
                        </div>
                        <div className="activity-content">
                          <p>{notification.message}</p>
                          <span className="activity-time">
                            {new Date(notification.createdAt).toLocaleDateString()}{' '}
                            {new Date(notification.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </span>
                        </div>
                      </div>
                    ))}
                    {notifications.length === 0 && (
                      <p className="no-activity">No recent activity</p>
                    )}
                  </div>
                </div>

                {/* Top Workers */}
                <div className="top-workers-card">
                  <h3>🏆 Top Rated Workers</h3>
                  <div className="workers-list">
                    {topWorkers.slice(0, 3).map((worker, index) => (
                      <div key={worker._id} className="worker-item">
                        <div className="worker-rank">#{index + 1}</div>
                        <div className="worker-avatar">
                          {worker.profileImage ? (
                            <img src={`http://localhost:5000${worker.profileImage}`} alt={worker.name} />
                          ) : (
                            <span>{worker.name?.charAt(0) || 'W'}</span>
                          )}
                        </div>
                        <div className="worker-info">
                          <h4>{worker.name || 'Unknown Worker'}</h4>
                          <div className="worker-rating">
                            <span className="stars">⭐ {(worker.rating?.average || 0).toFixed(1)}</span>
                            <span className="reviews">({worker.rating?.count || 0} reviews)</span>
                          </div>
                          <p className="worker-service">{worker.skills?.[0] || 'Various Skills'}</p>
                        </div>
                      </div>
                    ))}
                    {topWorkers.length === 0 && (
                      <p className="no-workers">No top workers to display</p>
                    )}
                  </div>
                </div>
              </div>

              <div className="section-column">
                {/* Active Jobs */}
                <div className="active-jobs-card">
                  <h3>💼 Active Jobs</h3>
                  <div className="jobs-list">
                    {activeJobs.slice(0, 3).map(job => (
                      <div key={job._id} className="job-item">
                        <div className="job-title">{job.title || 'Untitled Job'}</div>
                        <div className="job-status">
                          <span className={`status-badge ${job.status || 'pending'}`}>{job.status || 'Pending'}</span>
                        </div>
                        <div className="job-details">
                          <span className="job-budget">₹{(typeof job.budget === 'object' && job.budget !== null) ? (job.budget.estimated || job.budget.negotiable || 'N/A') : (job.budget || 'N/A')}</span>
                          <span className="job-due">Due: {job.dueDate ? new Date(job.dueDate).toLocaleDateString() : 'N/A'}</span>
                        </div>
                        {job.location?.coordinates?.latitude && job.location?.coordinates?.longitude && (
                          <div className="job-map-container">
                            <JobLocationMap job={job} height="100px" />
                          </div>
                        )}
                      </div>
                    ))}
                    {activeJobs.length === 0 && (
                      <p className="no-jobs">No active jobs</p>
                    )}
                  </div>
                </div>

                {/* Upcoming Payments */}
                <div className="payments-card">
                  <h3>💳 Upcoming Payments</h3>
                  <div className="payments-list">
                    {upcomingPayments.slice(0, 3).map(payment => (
                      <div key={payment._id} className="payment-item">
                        <div className="payment-info">
                          <div className="payment-title">Payment for {payment.jobTitle || 'Unknown Job'}</div>
                          <div className="payment-worker">to {payment.workerName || 'Unknown Worker'}</div>
                        </div>
                        <div className="payment-amount">₹{payment.amount || 0}</div>
                        <div className="payment-date">{payment.dueDate ? new Date(payment.dueDate).toLocaleDateString() : 'N/A'}</div>
                      </div>
                    ))}
                    {upcomingPayments.length === 0 && (
                      <p className="no-payments">No upcoming payments</p>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Quick Hire Services */}
            <div className="service-quick-links">
              <div className="section-header">
                <h3>🔧 Quick Hire Services</h3>
                <Link to="/browse-workers" className="view-all-btn">View All →</Link>
              </div>
              <div className="quick-links-grid">
                {categories.slice(0, 6).map(cat => (
                  <div key={cat.id} className="quick-link-card-wrapper">
                    <div 
                      className="quick-link-card" 
                      onClick={() => setSelectedCategory(cat.id)}
                      style={{borderColor: cat.color}}
                    >
                      <div className="service-icon" style={{color: cat.color}}>
                        {cat.icon}
                      </div>
                      <span className="service-label">{cat.label}</span>
                    </div>
                    {selectedCategory === cat.id && (
                      <div className="category-actions">
                        <button 
                          className="btn-estimate"
                          onClick={() => setIsEstimatorOpen(true)}
                        >
                          📐 Manpower Estimator
                        </button>
                        <button 
                          className="btn-nearby"
                          onClick={() => {
                            setIsEmergency(false);
                            setIsModalOpen(true);
                          }}
                        >
                          👥 Nearby Workers
                        </button>
                        <button 
                          className="btn-emergency"
                          onClick={() => {
                            setIsEmergency(true);
                            setIsModalOpen(true);
                          }}
                        >
                          🚨 Emergency Work
                        </button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <section className="recent-postings">
              <div className="section-header">
                <h3>📋 Recent Postings</h3>
                <div className="posting-actions">
                  <Link to="/post-job" className="post-job-btn">Post New Job</Link>
                  <Link to="/my-jobs" className="view-all-btn">View All</Link>
                </div>
              </div>
              <div className="jobs-container">
                {recentJobs.length > 0 ? (
                  recentJobs.map(job => (
                    <div key={job._id} className="job-item-card">
                      <div className="job-main">
                        <div className="job-icon" style={{background: categories.find(c => c.id === job.category)?.color || '#3B82F6'}}>
                          {categories.find(c => c.id === job.category)?.icon || '💼'}
                        </div>
                        <div className="job-details">
                          <h4>{job.title}</h4>
                          <p className="job-category">{job.category}</p>
                          <div className="job-meta">
                            <span className={`status-badge ${job.status}`}>{job.status}</span>
                            <span className="job-date">Posted: {new Date(job.createdAt).toLocaleDateString()}</span>
                          </div>
                        </div>
                      </div>
                      <div className="job-stats">
                        <div className="stat-item">
                          <span className="stat-label">Budget</span>
                          <span className="stat-value">₹{(typeof job.budget === 'object' && job.budget !== null) ? (job.budget.estimated || job.budget.negotiable || 'N/A') : (job.budget || 'N/A')}</span>
                        </div>
                        <div className="stat-item">
                          <span className="stat-label">Apps</span>
                          <span className="stat-value">{job.applications?.length || 0}</span>
                        </div>
                        <div className="job-actions">
                          <Link to={`/job/${job._id}`} className="manage-btn">Manage</Link>
                        </div>
                      </div>
                      {job.location?.coordinates?.latitude && job.location?.coordinates?.longitude && (
                        <div className="job-map-container">
                          <JobLocationMap job={job} height="120px" />
                        </div>
                      )}
                    </div>
                  ))
                ) : (
                  <div className="empty-state">
                    <span className="empty-icon">📋</span>
                    <h4>No Recent Postings</h4>
                    <p>Start by posting your first job to connect with skilled workers.</p>
                    <Link to="/post-job" className="primary-btn">Post Your First Job</Link>
                  </div>
                )}
              </div>
            </section>
          </>
        );
      case 'history':
        return (
          <div className="tab-content-area">
            <h2>Work History</h2>
            <p className="coming-soon">Your past hiring records and completed projects will appear here.</p>
          </div>
        );
      case 'notifications':
        return (
          <div className="tab-content-area">
            <h2>🔔 Notifications</h2>
            <div className="notifications-container">
              <div className="ai-help-prompt">
                <p>Need help with something? Ask our AI assistant!</p>
                <button className="ai-help-btn" onClick={() => setIsAIChatOpen(true)}>
                  🤖 Get AI Help
                </button>
              </div>
              {notifications.length > 0 ? (
                notifications.map(notification => (
                  <div key={notification._id} className={`notification-card ${notification.read ? 'read' : 'unread'}`}>
                    <div className="notification-header">
                      <span className="notification-type">
                        {notification.type === 'job_assigned' && '📋'}
                        {notification.type === 'job_accepted' && '✅'}
                        {notification.type === 'job_rejected' && '❌'}
                        {notification.type === 'application_received' && '📬'}
                        {notification.type === 'payment_received' && '💰'}
                        {notification.type === 'new_message' && '💬'}
                        {notification.type || '🔔'}
                      </span>
                      <span className="notification-time">
                        {new Date(notification.createdAt).toLocaleString()}
                      </span>
                    </div>
                    <div className="notification-body">
                      <h4>{notification.title}</h4>
                      <p>{notification.message}</p>
                      {notification.jobId && (
                        <Link to={`/job/${notification.jobId}`} className="notification-link">
                          View Job Details
                        </Link>
                      )}
                    </div>
                  </div>
                ))
              ) : (
                <div className="empty-notifications">
                  <span className="empty-icon">🔔</span>
                  <h3>No Notifications</h3>
                  <p>You're all caught up! Notifications will appear here when you receive updates.</p>
                </div>
              )}
            </div>
          </div>
        );
      case 'profile':
        return (
          <div className="tab-content-area">
            <h2>👤 My Profile</h2>
            <div className="profile-container">
              <div className="profile-section">
                <h3>Personal Information</h3>
                <div className="form-group">
                  <label>Full Name</label>
                  <input
                    type="text"
                    value={profileSettings.name}
                    onChange={(e) => handleProfileChange('name', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>Email Address</label>
                  <input
                    type="email"
                    value={profileSettings.email}
                    onChange={(e) => handleProfileChange('email', e.target.value)}
                    disabled
                  />
                  <small className="form-note">Email cannot be changed</small>
                </div>
                <div className="form-group">
                  <label>Phone Number</label>
                  <input
                    type="tel"
                    value={profileSettings.phone}
                    onChange={(e) => handleProfileChange('phone', e.target.value)}
                  />
                </div>
                <div className="form-group">
                  <label>Company Name</label>
                  <input
                    type="text"
                    value={profileSettings.company}
                    onChange={(e) => handleProfileChange('company', e.target.value)}
                    placeholder="Optional"
                  />
                </div>
              </div>

              <div className="profile-section">
                <h3>Preferences</h3>
                <div className="setting-item">
                  <label>
                    <input
                      type="checkbox"
                      checked={profileSettings.notifications}
                      onChange={(e) => handleProfileChange('notifications', e.target.checked)}
                    />
                    Enable Notifications
                  </label>
                </div>
                <div className="setting-item">
                  <label>
                    <input
                      type="checkbox"
                      checked={profileSettings.emailUpdates}
                      onChange={(e) => handleProfileChange('emailUpdates', e.target.checked)}
                    />
                    Email Updates
                  </label>
                </div>
              </div>

              <div className="profile-actions">
                <button className="save-btn" onClick={saveProfileSettings}>
                  Save Changes
                </button>
              </div>
            </div>
          </div>
        );
      case 'settings':
        return (
          <div className="tab-content-area">
            <h2>⚙️ Settings</h2>
            <div className="settings-container">
              <div className="settings-section">
                <h3>Account Settings</h3>
                <div className="setting-item">
                  <label>Profile Visibility</label>
                  <input type="checkbox" defaultChecked />
                  <span className="setting-description">Allow employers to find your profile</span>
                </div>
                <div className="setting-item">
                  <label>Email Notifications</label>
                  <input type="checkbox" defaultChecked />
                  <span className="setting-description">Receive email notifications for important updates</span>
                </div>
                <div className="setting-item">
                  <label>Two-Factor Authentication</label>
                  <input type="checkbox" />
                  <span className="setting-description">Add extra security to your account</span>
                </div>
              </div>

              <div className="settings-section">
                <h3>Privacy Settings</h3>
                <div className="setting-item">
                  <label>Show Contact Information</label>
                  <input type="checkbox" defaultChecked />
                  <span className="setting-description">Display your contact details to workers</span>
                </div>
                <div className="setting-item">
                  <label>Location Sharing</label>
                  <input type="checkbox" defaultChecked />
                  <span className="setting-description">Share your location for better worker matching</span>
                </div>
              </div>

              <div className="settings-section">
                <h3>Refer & Earn</h3>
                <div className="refer-section">
                  <p>Invite friends to join SkillConnect and earn rewards!</p>
                  <div className="refer-code">
                    <span>Your Referral Code: <strong>EMP-{user?._id?.substring(0, 6).toUpperCase()}</strong></span>
                    <button className="copy-btn">Copy</button>
                  </div>
                  <button className="share-btn">Share with Friends</button>
                </div>
              </div>

              <div className="settings-section">
                <h3>Help & Support</h3>
                <div className="help-section">
                  <p>Need assistance? Our AI-powered help center can answer your questions instantly.</p>
                  <button className="help-btn" onClick={() => setIsAIChatOpen(true)}>🤖 Chat with AI Assistant</button>
                  <button className="support-btn">📧 Contact Support</button>
                </div>
              </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-header">
          <div className="employer-avatar">
            {user?.name?.charAt(0) || 'E'}
          </div>
          <h3>{user?.name}</h3>
          <p>Employer</p>
        </div>
        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${activeTab === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActiveTab('dashboard')}
          >
            <span className="nav-icon">📊</span> Dashboard
          </button>
          <button 
            className={`nav-item ${activeTab === 'notifications' ? 'active' : ''}`}
            onClick={() => setActiveTab('notifications')}
          >
            <span className="nav-icon">🔔</span> Notifications
            {notifications.filter(n => !n.read).length > 0 && (
              <span className="notification-badge">
                {notifications.filter(n => !n.read).length}
              </span>
            )}
          </button>
          <button 
            className={`nav-item ${activeTab === 'profile' ? 'active' : ''}`}
            onClick={() => setActiveTab('profile')}
          >
            <span className="nav-icon">👤</span> Profile
          </button>
          <button 
            className={`nav-item ${activeTab === 'history' ? 'active' : ''}`}
            onClick={() => setActiveTab('history')}
          >
            <span className="nav-icon">📜</span> History
          </button>
          <button 
            className={`nav-item ${activeTab === 'settings' ? 'active' : ''}`}
            onClick={() => setActiveTab('settings')}
          >
            <span className="nav-icon">⚙️</span> Settings
          </button>
          <button 
            className="nav-item logout-btn"
            onClick={handleLogout}
          >
            <span className="nav-icon">🚪</span> Logout
          </button>
        </nav>
      </aside>

      <main className="dashboard-main">
        {loading && activeTab === 'dashboard' ? (
          <div className="loading">Loading...</div>
        ) : (
          renderContent()
        )}
      </main>

      <NearbyWorkersModal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false);
          setSelectedCategory(null);
        }}
        category={selectedCategory}
        isEmergency={isEmergency}
      />

      <ServiceEstimatorModal
        isOpen={isEstimatorOpen}
        onClose={() => setIsEstimatorOpen(false)}
        service={activeCategory}
      />
      
      <AIChat 
        isOpen={isAIChatOpen} 
        onClose={() => setIsAIChatOpen(false)} 
      />
    </div>
  );
};
export default EmployerDashboard;
